    biz_type, demand_id, order_id, sender_id, receiver_id, msg_type,
    content, file_url, extra_json, read_status, status, read_at, created_at
) values (
    #{bizType}, #{demandId}, #{orderId}, #{senderId}, #{receiverId}, #{msgType},
    #{content}, #{fileUrl}, #{extraJson}, #{readStatus}, #{status}, #{readAt}, #{createdAt}
)

mapper.select:
select from `chat_message` where status in (1, 2) and biz_type = #{bizType}
and demand_id = #{demandId}
and demand_id is null
and order_id = #{orderId}
and order_id is null
and ( (sender_id = #{leftUserId} and receiver_id = #{rightUserId}) or (sender_id = #{rightUserId} and receiver_id = #{leftUserId}) ) order by created_at asc, id asc

